import React, { useState, useEffect } from 'react';
import {
  Box,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  CircularProgress,
  Alert,
  Grid
} from '@mui/material';
import dashboardService from '../../services/dashboardService';

const HistoricoTrades = () => {
  const [trades, setTrades] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [stats, setStats] = useState({
    totalTrades: 0,
    winRate: 0,
    totalPnl: 0,
    winningTrades: 0,
    losingTrades: 0
  });

  const loadTrades = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await dashboardService.getClosedTrades();
      
      // Verifica se a resposta e os trades existem
      if (!response || !response.trades) {
        throw new Error('Dados de trades não disponíveis');
      }

      setTrades(response.trades);
      
      // Calcula estatísticas apenas se houver trades
      const totalTrades = response.trades.length;
      if (totalTrades > 0) {
        const winningTrades = response.trades.filter(trade => parseFloat(trade.pnl) > 0).length;
        const losingTrades = response.trades.filter(trade => parseFloat(trade.pnl) <= 0).length;
        const winRate = (winningTrades / totalTrades) * 100;
        const totalPnl = response.trades.reduce((sum, trade) => sum + parseFloat(trade.pnl || 0), 0);

        setStats({
          totalTrades,
          winRate,
          totalPnl,
          winningTrades,
          losingTrades
        });
      }
    } catch (error) {
      console.error('Erro ao carregar trades:', error);
      setError(error.message || 'Erro ao carregar histórico de trades');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadTrades();
  }, []);

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 8
    }).format(value);
  };

  const formatPercentage = (value) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'percent',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value / 100);
  };

  if (loading) {
    return (
      <Box sx={{ p: 3, textAlign: 'center' }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ p: 3 }}>
        <Alert severity="error">{error}</Alert>
      </Box>
    );
  }

  return (
    <Box sx={{ width: '100%', bgcolor: 'background.paper', borderRadius: 1, overflow: 'hidden' }}>
      <Box sx={{ p: 2, borderBottom: 1, borderColor: 'divider' }}>
        <Typography variant="h6" component="div" sx={{ color: 'text.primary' }}>
          Histórico de Trades
        </Typography>
      </Box>

      {/* Estatísticas */}
      <Grid container spacing={2} sx={{ p: 2 }}>
        <Grid item xs={12} sm={4} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Total de Trades</Typography>
            <Typography variant="h6">{stats.totalTrades}</Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={4} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Win Rate</Typography>
            <Typography variant="h6">{formatPercentage(stats.winRate)}</Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={4} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">PnL Total</Typography>
            <Typography variant="h6" color={stats.totalPnl >= 0 ? 'success.main' : 'error.main'}>
              {formatCurrency(stats.totalPnl)}
            </Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Trades Ganhos</Typography>
            <Typography variant="h6" color="success.main">{stats.winningTrades}</Typography>
          </Box>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Box sx={{ textAlign: 'center', p: 1 }}>
            <Typography variant="body2" color="text.secondary">Trades Perdidos</Typography>
            <Typography variant="h6" color="error.main">{stats.losingTrades}</Typography>
          </Box>
        </Grid>
      </Grid>

      {/* Tabela de Trades */}
      <TableContainer component={Paper} sx={{ maxHeight: 400 }}>
        <Table stickyHeader>
          <TableHead>
            <TableRow>
              <TableCell>Par</TableCell>
              <TableCell>Lado</TableCell>
              <TableCell>Tamanho</TableCell>
              <TableCell>Alavancagem</TableCell>
              <TableCell>Preço de Entrada</TableCell>
              <TableCell>Preço de Saída</TableCell>
              <TableCell>PnL</TableCell>
              <TableCell>ROE%</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {trades.length === 0 ? (
              <TableRow>
                <TableCell colSpan={8} align="center">
                  <Typography variant="body2" color="text.secondary">
                    Nenhum trade fechado encontrado
                  </Typography>
                </TableCell>
              </TableRow>
            ) : (
              trades.map((trade, index) => (
                <TableRow key={index}>
                  <TableCell>{trade.symbol}</TableCell>
                  <TableCell sx={{ color: trade.side === 'buy' ? 'success.main' : 'error.main' }}>
                    {trade.side === 'buy' ? 'LONG' : 'SHORT'}
                  </TableCell>
                  <TableCell>{trade.size}</TableCell>
                  <TableCell>{trade.leverage}x</TableCell>
                  <TableCell>{trade.entry_price}</TableCell>
                  <TableCell>{trade.exit_price}</TableCell>
                  <TableCell sx={{ color: parseFloat(trade.pnl) >= 0 ? 'success.main' : 'error.main' }}>
                    {formatCurrency(trade.pnl)}
                  </TableCell>
                  <TableCell sx={{ color: parseFloat(trade.roe) >= 0 ? 'success.main' : 'error.main' }}>
                    {formatPercentage(trade.roe)}
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
};

export default HistoricoTrades;
